const markdownData = {"01_SQL.md": "# \ud83d\udcca SQL \u8cc7\u6599\u5eab\u67e5\u8a62\u8a9e\u8a00 \u2014 \u8003\u8a66\u91cd\u9ede\u7b46\u8a18\n> \u4f54\u6bd4\uff1a**30%** \uff5c \u512a\u5148\u5ea6\uff1a\u2b50\u2b50\u2b50 \u6700\u9ad8\n\n---\n\n## \u4e00\u3001SQL \u8a9e\u8a00\u5206\u985e\n\n| \u5206\u985e | \u5168\u540d | \u7528\u9014 | \u5e38\u898b\u6307\u4ee4 |\n|------|------|------|----------|\n| **DDL** | Data Definition Language | \u5b9a\u7fa9\u8cc7\u6599\u7d50\u69cb | `CREATE`, `ALTER`, `DROP`, `TRUNCATE` |\n| **DML** | Data Manipulation Language | \u64cd\u4f5c\u8cc7\u6599\u5167\u5bb9 | `SELECT`, `INSERT`, `UPDATE`, `DELETE` |\n| **DCL** | Data Control Language | \u6b0a\u9650\u63a7\u5236 | `GRANT`, `REVOKE` |\n| **TCL** | Transaction Control Language | \u4ea4\u6613\u63a7\u5236 | `COMMIT`, `ROLLBACK`, `SAVEPOINT` |\n\n> \ud83d\udca1 **\u53e3\u8a23**\uff1aDDL \u7ba1\u7d50\u69cb\u3001DML \u7ba1\u8cc7\u6599\u3001DCL \u7ba1\u6b0a\u9650\u3001TCL \u7ba1\u4ea4\u6613\n\n---\n\n## \u4e8c\u3001SELECT \u67e5\u8a62\u8a9e\u6cd5\uff08\u6700\u5e38\u8003\uff01\uff09\n\n### \u57fa\u672c\u8a9e\u6cd5\u7d50\u69cb\n```sql\nSELECT \u6b04\u4f4d1, \u6b04\u4f4d2        -- \u8981\u986f\u793a\u7684\u6b04\u4f4d\nFROM \u8cc7\u6599\u8868                  -- \u5f9e\u54ea\u500b\u8868\nWHERE \u689d\u4ef6                   -- \u7be9\u9078\u689d\u4ef6\nGROUP BY \u5206\u7d44\u6b04\u4f4d            -- \u5206\u7d44\nHAVING \u5206\u7d44\u5f8c\u689d\u4ef6            -- \u5206\u7d44\u5f8c\u518d\u7be9\u9078\nORDER BY \u6392\u5e8f\u6b04\u4f4d ASC/DESC   -- \u6392\u5e8f\nLIMIT \u6578\u91cf                   -- \u9650\u5236\u7b46\u6578\n```\n\n### \u26a0\ufe0f \u57f7\u884c\u9806\u5e8f\uff08\u5f88\u91cd\u8981\uff01\u548c\u5beb\u7684\u9806\u5e8f\u4e0d\u540c\uff09\n```\nFROM \u2192 WHERE \u2192 GROUP BY \u2192 HAVING \u2192 SELECT \u2192 ORDER BY \u2192 LIMIT\n```\n\n> \ud83d\udca1 **\u53e3\u8a23**\uff1a**F**rom **W**here **G**roup **H**aving **S**elect **O**rder **L**imit\n> \u300c**\u5bcc\u5a46** **\u6211** **\u54e5** **\u5f88** **\u5e25** **\u5662** **\u6e9c**\u300d\n\n---\n\n## \u4e09\u3001WHERE \u689d\u4ef6\u904b\u7b97\u5b50\n\n| \u904b\u7b97\u5b50 | \u8aaa\u660e | \u7bc4\u4f8b |\n|--------|------|------|\n| `=`, `!=`, `<>` | \u7b49\u65bc\u3001\u4e0d\u7b49\u65bc | `WHERE age = 25` |\n| `>`, `<`, `>=`, `<=` | \u6bd4\u8f03 | `WHERE salary >= 50000` |\n| `AND`, `OR`, `NOT` | \u908f\u8f2f\u7d44\u5408 | `WHERE age > 20 AND city = '\u53f0\u5317'` |\n| `BETWEEN` | \u4ecb\u65bc\u4e4b\u9593 | `WHERE age BETWEEN 20 AND 30` |\n| `IN` | \u5728\u5217\u8868\u4e2d | `WHERE city IN ('\u53f0\u5317', '\u9ad8\u96c4')` |\n| `LIKE` | \u6a21\u7cca\u641c\u5c0b | `WHERE name LIKE '\u6797%'` |\n| `IS NULL` / `IS NOT NULL` | \u7a7a\u503c\u5224\u65b7 | `WHERE email IS NOT NULL` |\n\n### LIKE \u842c\u7528\u5b57\u5143\n| \u7b26\u865f | \u610f\u7fa9 | \u7bc4\u4f8b | \u5339\u914d |\n|------|------|------|------|\n| `%` | \u4efb\u610f\u591a\u500b\u5b57\u5143 | `'\u6797%'` | \u6797\u5c0f\u660e\u3001\u6797\u5927\u5927 |\n| `_` | \u4efb\u610f\u4e00\u500b\u5b57\u5143 | `'\u6797_\u660e'` | \u6797\u5c0f\u660e\uff08\u4e0d\u542b\u6797\u5927\u5927\u660e\uff09 |\n\n---\n\n## \u56db\u3001\u805a\u5408\u51fd\u6578\uff08Aggregate Functions\uff09\n\n| \u51fd\u6578 | \u529f\u80fd | \u7bc4\u4f8b |\n|------|------|------|\n| `COUNT(*)` | \u8a08\u7b97\u7b46\u6578 | `SELECT COUNT(*) FROM employees` |\n| `SUM(\u6b04\u4f4d)` | \u52a0\u7e3d | `SELECT SUM(salary) FROM employees` |\n| `AVG(\u6b04\u4f4d)` | \u5e73\u5747 | `SELECT AVG(salary) FROM employees` |\n| `MAX(\u6b04\u4f4d)` | \u6700\u5927\u503c | `SELECT MAX(salary) FROM employees` |\n| `MIN(\u6b04\u4f4d)` | \u6700\u5c0f\u503c | `SELECT MIN(salary) FROM employees` |\n\n> \u26a0\ufe0f **\u6ce8\u610f**\uff1a`COUNT(*)` \u5305\u542b NULL\uff0c`COUNT(\u6b04\u4f4d)` \u4e0d\u5305\u542b NULL\n\n---\n\n## \u4e94\u3001GROUP BY \u8207 HAVING\n\n### GROUP BY \u2014 \u5206\u7d44\u7d71\u8a08\n```sql\n-- \u7d71\u8a08\u6bcf\u500b\u90e8\u9580\u7684\u4eba\u6578\nSELECT department, COUNT(*) AS \u4eba\u6578\nFROM employees\nGROUP BY department;\n```\n\n### HAVING \u2014 \u5206\u7d44\u5f8c\u518d\u7be9\u9078\n```sql\n-- \u627e\u51fa\u4eba\u6578\u8d85\u904e 10 \u4eba\u7684\u90e8\u9580\nSELECT department, COUNT(*) AS \u4eba\u6578\nFROM employees\nGROUP BY department\nHAVING COUNT(*) > 10;\n```\n\n> \u26a0\ufe0f **WHERE vs HAVING \u5dee\u7570**\uff1a\n> - `WHERE`\uff1a\u5728\u5206\u7d44**\u4e4b\u524d**\u7be9\u9078\uff08\u904e\u6ffe\u539f\u59cb\u8cc7\u6599\uff09\n> - `HAVING`\uff1a\u5728\u5206\u7d44**\u4e4b\u5f8c**\u7be9\u9078\uff08\u904e\u6ffe\u805a\u5408\u7d50\u679c\uff09\n\n---\n\n## \u516d\u3001JOIN \u8868\u683c\u9023\u63a5\uff08\u5fc5\u8003\uff01\uff09\n\n### \u56db\u7a2e JOIN \u985e\u578b\n\n```\n      A \u8868          B \u8868\n\n  \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510   \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n  \u2502         \u2502   \u2502         \u2502\n  \u2502    A  \u250c\u2500\u253c\u2500\u2500\u2500\u253c\u2500\u2510  B    \u2502\n  \u2502       \u2502 \u2502   \u2502 \u2502       \u2502\n  \u2502       \u2502\u4ea4\u2502   \u2502\u96c6\u2502       \u2502\n  \u2502       \u2514\u2500\u253c\u2500\u2500\u2500\u253c\u2500\u2518       \u2502\n  \u2502         \u2502   \u2502         \u2502\n  \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518   \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n```\n\n| JOIN \u985e\u578b | \u8aaa\u660e | \u7d50\u679c |\n|-----------|------|------|\n| `INNER JOIN` | \u4ea4\u96c6 | \u53ea\u56de\u50b3\u5169\u8868\u90fd\u6709\u5339\u914d\u7684\u8cc7\u6599 |\n| `LEFT JOIN` | \u5de6\u8868\u5168\u90e8 + \u53f3\u8868\u5339\u914d | \u5de6\u8868\u5168\u90e8\u4fdd\u7559\uff0c\u53f3\u8868\u6c92\u5339\u914d\u7684\u586b NULL |\n| `RIGHT JOIN` | \u53f3\u8868\u5168\u90e8 + \u5de6\u8868\u5339\u914d | \u53f3\u8868\u5168\u90e8\u4fdd\u7559\uff0c\u5de6\u8868\u6c92\u5339\u914d\u7684\u586b NULL |\n| `FULL OUTER JOIN` | \u806f\u96c6 | \u5169\u8868\u5168\u90e8\u4fdd\u7559\uff0c\u6c92\u5339\u914d\u7684\u586b NULL |\n\n### \u7bc4\u4f8b\n```sql\n-- INNER JOIN\uff1a\u627e\u51fa\u6709\u90e8\u9580\u7684\u54e1\u5de5\nSELECT e.name, d.dept_name\nFROM employees e\nINNER JOIN departments d ON e.dept_id = d.id;\n\n-- LEFT JOIN\uff1a\u5217\u51fa\u6240\u6709\u54e1\u5de5\uff08\u5305\u542b\u6c92\u90e8\u9580\u7684\uff09\nSELECT e.name, d.dept_name\nFROM employees e\nLEFT JOIN departments d ON e.dept_id = d.id;\n```\n\n> \ud83d\udca1 **\u53e3\u8a23**\uff1aINNER \u53d6\u4ea4\u96c6\u3001LEFT \u7559\u5de6\u908a\u3001RIGHT \u7559\u53f3\u908a\u3001FULL \u5168\u90fd\u7559\n\n---\n\n## \u4e03\u3001\u5b50\u67e5\u8a62\uff08Subquery\uff09\n\n### \u5728 WHERE \u4e2d\u4f7f\u7528\n```sql\n-- \u627e\u51fa\u85aa\u6c34\u9ad8\u65bc\u5e73\u5747\u7684\u54e1\u5de5\nSELECT name, salary\nFROM employees\nWHERE salary > (SELECT AVG(salary) FROM employees);\n```\n\n### \u642d\u914d IN \u4f7f\u7528\n```sql\n-- \u627e\u51fa\u5728\u53f0\u5317\u5206\u90e8\u5de5\u4f5c\u7684\u54e1\u5de5\nSELECT name\nFROM employees\nWHERE dept_id IN (SELECT id FROM departments WHERE city = '\u53f0\u5317');\n```\n\n### \u642d\u914d EXISTS \u4f7f\u7528\n```sql\n-- \u627e\u51fa\u6709\u8a02\u55ae\u7684\u5ba2\u6236\nSELECT name\nFROM customers c\nWHERE EXISTS (SELECT 1 FROM orders o WHERE o.customer_id = c.id);\n```\n\n> \ud83d\udca1 **IN vs EXISTS**\uff1a\n> - `IN`\uff1a\u9069\u5408\u5b50\u67e5\u8a62\u7d50\u679c\u96c6\u8f03\u5c0f\u6642\n> - `EXISTS`\uff1a\u9069\u5408\u5b50\u67e5\u8a62\u7d50\u679c\u96c6\u8f03\u5927\u6642\uff08\u6548\u7387\u8f03\u9ad8\uff09\n\n---\n\n## \u516b\u3001CASE WHEN \u689d\u4ef6\u8868\u9054\u5f0f\n\n```sql\n-- \u6839\u64da\u85aa\u6c34\u5206\u7d1a\nSELECT name, salary,\n    CASE\n        WHEN salary >= 80000 THEN '\u9ad8\u85aa'\n        WHEN salary >= 50000 THEN '\u4e2d\u85aa'\n        ELSE '\u4f4e\u85aa'\n    END AS \u85aa\u8cc7\u7b49\u7d1a\nFROM employees;\n```\n\n---\n\n## \u4e5d\u3001DDL \u8cc7\u6599\u5b9a\u7fa9\n\n### CREATE TABLE\n```sql\nCREATE TABLE employees (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    name VARCHAR(50) NOT NULL,\n    email VARCHAR(100) UNIQUE,\n    salary DECIMAL(10, 2) DEFAULT 0,\n    dept_id INT,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (dept_id) REFERENCES departments(id)\n);\n```\n\n### \u5e38\u898b\u7d04\u675f\u689d\u4ef6\n| \u7d04\u675f | \u8aaa\u660e |\n|------|------|\n| `PRIMARY KEY` | \u4e3b\u9375\uff0c\u552f\u4e00\u4e14\u4e0d\u53ef NULL |\n| `FOREIGN KEY` | \u5916\u9375\uff0c\u53c3\u7167\u5176\u4ed6\u8868\u7684\u4e3b\u9375 |\n| `NOT NULL` | \u4e0d\u53ef\u70ba\u7a7a |\n| `UNIQUE` | \u552f\u4e00\u503c |\n| `DEFAULT` | \u9810\u8a2d\u503c |\n| `CHECK` | \u6aa2\u67e5\u689d\u4ef6 |\n\n### ALTER TABLE\n```sql\nALTER TABLE employees ADD COLUMN phone VARCHAR(20);    -- \u65b0\u589e\u6b04\u4f4d\nALTER TABLE employees DROP COLUMN phone;               -- \u522a\u9664\u6b04\u4f4d\nALTER TABLE employees MODIFY COLUMN name VARCHAR(100); -- \u4fee\u6539\u6b04\u4f4d\n```\n\n---\n\n## \u5341\u3001DML \u8cc7\u6599\u64cd\u4f5c\n\n### INSERT\n```sql\nINSERT INTO employees (name, email, salary)\nVALUES ('\u6797\u5c0f\u660e', 'ming@example.com', 55000);\n```\n\n### UPDATE\n```sql\nUPDATE employees\nSET salary = 60000\nWHERE name = '\u6797\u5c0f\u660e';\n```\n\n### DELETE\n```sql\nDELETE FROM employees\nWHERE id = 5;\n```\n\n> \u26a0\ufe0f **DELETE vs TRUNCATE vs DROP**\uff1a\n> - `DELETE`\uff1a\u522a\u9664\u7279\u5b9a\u8cc7\u6599\uff08\u53ef\u56de\u5fa9\u3001\u53ef\u52a0 WHERE\uff09\n> - `TRUNCATE`\uff1a\u6e05\u7a7a\u6574\u5f35\u8868\u7684\u8cc7\u6599\uff08\u4e0d\u53ef\u56de\u5fa9\u3001\u66f4\u5feb\uff09\n> - `DROP`\uff1a\u76f4\u63a5\u522a\u9664\u6574\u5f35\u8868\uff08\u7d50\u69cb\u4e5f\u522a\u6389\uff09\n\n---\n\n## \u5341\u4e00\u3001VIEW \u8996\u5716\n\n```sql\n-- \u5efa\u7acb\u8996\u5716\nCREATE VIEW high_salary_employees AS\nSELECT name, salary, department\nFROM employees\nWHERE salary > 70000;\n\n-- \u4f7f\u7528\u8996\u5716\uff08\u7576\u6210\u666e\u901a\u8868\u67e5\u8a62\uff09\nSELECT * FROM high_salary_employees;\n```\n\n> \ud83d\udca1 \u8996\u5716 = **\u865b\u64ec\u7684\u8868**\uff0c\u4e0d\u6703\u5b58\u5be6\u969b\u8cc7\u6599\uff0c\u6bcf\u6b21\u67e5\u8a62\u90fd\u91cd\u65b0\u57f7\u884c\n\n---\n\n## \u5341\u4e8c\u3001INDEX \u7d22\u5f15\n\n```sql\n-- \u5efa\u7acb\u7d22\u5f15\uff08\u52a0\u901f\u67e5\u8a62\uff09\nCREATE INDEX idx_employee_name ON employees(name);\n\n-- \u5efa\u7acb\u8907\u5408\u7d22\u5f15\nCREATE INDEX idx_dept_salary ON employees(dept_id, salary);\n```\n\n> \ud83d\udca1 \u7d22\u5f15\u7684\u53d6\u6368\uff1a\n> - \u2705 \u512a\u9ede\uff1a\u5927\u5e45\u52a0\u901f SELECT \u67e5\u8a62\n> - \u274c \u7f3a\u9ede\uff1a\u6703\u8b93 INSERT/UPDATE/DELETE \u8b8a\u6162\uff08\u56e0\u70ba\u8981\u540c\u6b65\u66f4\u65b0\u7d22\u5f15\uff09\n\n---\n\n## \u5341\u4e09\u3001Transaction \u4ea4\u6613\n\n```sql\nBEGIN TRANSACTION;\n\nUPDATE accounts SET balance = balance - 1000 WHERE id = 1;\nUPDATE accounts SET balance = balance + 1000 WHERE id = 2;\n\nCOMMIT;  -- \u78ba\u8a8d\u4ea4\u6613\uff08\u5169\u7b46\u90fd\u6210\u529f\u624d\u57f7\u884c\uff09\n-- \u6216\nROLLBACK; -- \u53d6\u6d88\u4ea4\u6613\uff08\u4efb\u4e00\u7b46\u5931\u6557\u5c31\u5168\u90e8\u56de\u5fa9\uff09\n```\n\n### ACID \u7279\u6027\uff08\u5fc5\u8003\uff01\uff09\n| \u7279\u6027 | \u82f1\u6587 | \u8aaa\u660e |\n|------|------|------|\n| **A** \u539f\u5b50\u6027 | Atomicity | \u4ea4\u6613\u4e2d\u7684\u64cd\u4f5c\u8981\u561b\u5168\u6210\u529f\u3001\u8981\u561b\u5168\u5931\u6557 |\n| **C** \u4e00\u81f4\u6027 | Consistency | \u4ea4\u6613\u524d\u5f8c\u8cc7\u6599\u5fc5\u9808\u7dad\u6301\u4e00\u81f4\u72c0\u614b |\n| **I** \u9694\u96e2\u6027 | Isolation | \u591a\u500b\u4ea4\u6613\u540c\u6642\u9032\u884c\u6642\u4e92\u4e0d\u5f71\u97ff |\n| **D** \u6301\u4e45\u6027 | Durability | \u4ea4\u6613\u5b8c\u6210\u5f8c\u7684\u7d50\u679c\u6703\u6c38\u4e45\u4fdd\u5b58 |\n\n> \ud83d\udca1 **\u53e3\u8a23**\uff1aACID = \u9178 \u2192 \u4ea4\u6613\u8981\u50cf\u300c\u9178\u300d\u4e00\u6a23\u4fdd\u6301\u7a69\u5b9a\u4e0d\u8b8a\u8cea\n\n---\n\n## \u5e38\u898b\u8003\u984c\u901f\u8a18\n\n| \u984c\u578b | \u95dc\u9375\u5b57 |\n|------|--------|\n| \u67e5\u8a62\u67d0\u500b\u689d\u4ef6\u7684\u8cc7\u6599 | SELECT + WHERE |\n| \u7d71\u8a08\u6bcf\u500b\u5206\u985e\u7684\u6578\u91cf | GROUP BY + COUNT |\n| \u627e\u51fa\u6700\u5927/\u6700\u5c0f/\u5e73\u5747 | MAX / MIN / AVG |\n| \u5169\u8868\u5408\u4f75\u67e5\u8a62 | JOIN + ON |\n| \u904e\u6ffe\u805a\u5408\u7d50\u679c | HAVING |\n| \u5224\u65b7\u7a7a\u503c | IS NULL / IS NOT NULL |\n| \u6a21\u7cca\u641c\u5c0b | LIKE + % \u6216 _ |\n| \u689d\u4ef6\u5206\u652f | CASE WHEN |\n| \u5de2\u72c0\u67e5\u8a62 | \u5b50\u67e5\u8a62 (Subquery) |\n\n---\n\n*\ud83d\udcdd by \u751c\u8766 \ud83c\udf64 | 2026.04.20*\n", "02_BigData.md": "# \ud83d\udce1 \u5927\u6578\u64da\u57fa\u672c\u6982\u8981 \u2014 \u8003\u8a66\u91cd\u9ede\u7b46\u8a18\n> \u4f54\u6bd4\uff1a**20%** \uff5c \u512a\u5148\u5ea6\uff1a\u2b50\u2b50\n\n---\n\n## \u4e00\u3001\u4ec0\u9ebc\u662f\u5927\u6578\u64da\uff1f\n\n\u5927\u6578\u64da\uff08Big Data\uff09\u6307\u7684\u662f**\u50b3\u7d71\u8cc7\u6599\u8655\u7406\u5de5\u5177\u7121\u6cd5\u6709\u6548\u8655\u7406**\u7684\u8d85\u5927\u898f\u6a21\u8cc7\u6599\u96c6\u5408\u3002\n\n### \u5927\u6578\u64da\u7684 5V \u7279\u6027\uff08\u5fc5\u8003\uff01\uff09\n\n| V | \u82f1\u6587 | \u4e2d\u6587 | \u8aaa\u660e |\n|---|------|------|------|\n| **V1** | Volume | \u91cf\u5927 | \u8cc7\u6599\u91cf\u6975\u5927\uff08TB\u3001PB \u7b49\u7d1a\uff09 |\n| **V2** | Velocity | \u901f\u5feb | \u8cc7\u6599\u7522\u751f\u8207\u8655\u7406\u901f\u5ea6\u6975\u5feb |\n| **V3** | Variety | \u591a\u6a23 | \u8cc7\u6599\u985e\u578b\u591a\u5143\uff08\u6587\u5b57\u3001\u5716\u7247\u3001\u5f71\u7247\u2026\uff09 |\n| **V4** | Veracity | \u771f\u5be6 | \u8cc7\u6599\u54c1\u8cea\u8207\u53ef\u4fe1\u5ea6 |\n| **V5** | Value | \u50f9\u503c | \u5f9e\u6d77\u91cf\u8cc7\u6599\u4e2d\u8403\u53d6\u51fa\u6709\u50f9\u503c\u7684\u8cc7\u8a0a |\n\n> \ud83d\udca1 **\u53e3\u8a23**\uff1a\u5927\u6578\u64da\u5c31\u50cf\u5927\u6d77 \u2192\u300c**\u91cf\u5927\u3001\u901f\u5feb\u3001\u591a\u6a23\u3001\u771f\u5be6\u3001\u6709\u50f9\u503c**\u300d\n\n> \u26a0\ufe0f \u6709\u4e9b\u984c\u76ee\u53ea\u8003 3V\uff08Volume, Velocity, Variety\uff09\uff0c\u6709\u4e9b\u8003 5V\uff0c\u90fd\u8981\u6703\uff01\n\n---\n\n## \u4e8c\u3001\u7d50\u69cb\u5316 vs \u534a\u7d50\u69cb\u5316 vs \u975e\u7d50\u69cb\u5316\u8cc7\u6599\n\n| \u985e\u578b | \u8aaa\u660e | \u7bc4\u4f8b |\n|------|------|------|\n| **\u7d50\u69cb\u5316\u8cc7\u6599** | \u6709\u56fa\u5b9a\u683c\u5f0f\uff0c\u53ef\u5b58\u653e\u5728\u95dc\u806f\u5f0f\u8cc7\u6599\u5eab | Excel \u8868\u683c\u3001SQL \u8cc7\u6599\u5eab\u3001CSV |\n| **\u534a\u7d50\u69cb\u5316\u8cc7\u6599** | \u6709\u4e00\u5b9a\u7d50\u69cb\u4f46\u4e0d\u56b4\u683c | JSON\u3001XML\u3001HTML\u3001Log \u6a94 |\n| **\u975e\u7d50\u69cb\u5316\u8cc7\u6599** | \u6c92\u6709\u56fa\u5b9a\u683c\u5f0f | \u5716\u7247\u3001\u5f71\u7247\u3001\u97f3\u8a0a\u3001\u793e\u7fa4\u8cbc\u6587\u3001Email |\n\n> \ud83d\udca1 \u5927\u6578\u64da\u4e2d\uff0c\u7d04 **80% \u662f\u975e\u7d50\u69cb\u5316\u8cc7\u6599**\n\n---\n\n## \u4e09\u3001Hadoop \u751f\u614b\u7cfb\uff08\u91cd\u8981\uff01\uff09\n\n### Hadoop \u6838\u5fc3\u5143\u4ef6\n\n| \u5143\u4ef6 | \u529f\u80fd | \u767d\u8a71\u8aaa\u660e |\n|------|------|----------|\n| **HDFS** | \u5206\u6563\u5f0f\u6a94\u6848\u7cfb\u7d71 | \u628a\u5927\u6a94\u6848\u5207\u6210\u5c0f\u584a\uff0c\u5206\u6563\u5b58\u5728\u591a\u53f0\u96fb\u8166\u4e0a |\n| **MapReduce** | \u5206\u6563\u5f0f\u904b\u7b97\u6846\u67b6 | \u628a\u5927\u4efb\u52d9\u62c6\u6210\u5c0f\u4efb\u52d9\uff0c\u5206\u7d66\u591a\u53f0\u96fb\u8166\u8655\u7406\uff0c\u6700\u5f8c\u5408\u4f75\u7d50\u679c |\n| **YARN** | \u8cc7\u6e90\u7ba1\u7406 | \u8ca0\u8cac\u5206\u914d CPU\u3001\u8a18\u61b6\u9ad4\u7d66\u5404\u500b\u4efb\u52d9 |\n\n### HDFS \u67b6\u69cb\n```\n                \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n                \u2502  NameNode    \u2502 \u2190 \u7ba1\u7406\u54e1\uff1a\u77e5\u9053\u8cc7\u6599\u5b58\u5728\u54ea\n                \u2502 \uff08\u4e3b\u7bc0\u9ede\uff09    \u2502\n                \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u252c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n           \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u253c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n     \u250c\u2500\u2500\u2500\u2500\u2500\u2534\u2500\u2500\u2500\u2500\u2500\u2510 \u250c\u2500\u2500\u2500\u2534\u2500\u2500\u2500\u2500\u2500\u2510 \u250c\u2500\u2500\u2534\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n     \u2502 DataNode 1\u2502 \u2502DataNode2\u2502 \u2502DataNode3\u2502 \u2190 \u5de5\u4eba\uff1a\u5be6\u969b\u5b58\u653e\u8cc7\u6599\n     \u2502  \u8cc7\u6599\u584aA  \u2502 \u2502 \u8cc7\u6599\u584aB \u2502 \u2502 \u8cc7\u6599\u584aC \u2502\n     \u2502  \u8cc7\u6599\u584aB  \u2502 \u2502 \u8cc7\u6599\u584aC \u2502 \u2502 \u8cc7\u6599\u584aA \u2502 \u2190 \u6bcf\u584a\u8cc7\u6599\u5b58 3 \u4efd\uff08\u5099\u4efd\uff09\n     \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518 \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518 \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n```\n\n### MapReduce \u904b\u4f5c\u6d41\u7a0b\n```\n\u539f\u59cb\u8cc7\u6599 \u2192 Map\uff08\u62c6\u89e3\uff09 \u2192 Shuffle\uff08\u6392\u5e8f\u5206\u7d44\uff09 \u2192 Reduce\uff08\u5408\u4f75\uff09 \u2192 \u7d50\u679c\n\n\u7bc4\u4f8b\uff1a\u7d71\u8a08\u6587\u7ae0\u4e2d\u6bcf\u500b\u5b57\u51fa\u73fe\u5e7e\u6b21\n  Map:    \"Hello World Hello\" \u2192 (Hello,1)(World,1)(Hello,1)\n  Shuffle: (Hello,[1,1])(World,[1])\n  Reduce:  (Hello,2)(World,1)\n```\n\n---\n\n## \u56db\u3001Hadoop \u751f\u614b\u5708\u5e38\u898b\u5de5\u5177\n\n| \u5de5\u5177 | \u529f\u80fd | \u767d\u8a71\u8aaa\u660e |\n|------|------|----------|\n| **Hive** | \u8cc7\u6599\u5009\u5132 | \u8b93\u4f60\u7528\u985e\u4f3c SQL \u7684\u8a9e\u6cd5\u67e5\u8a62 Hadoop \u4e0a\u7684\u5927\u6578\u64da |\n| **Pig** | \u8cc7\u6599\u6d41\u8655\u7406 | \u7528\u8173\u672c\u8a9e\u8a00\u505a\u8cc7\u6599\u8f49\u63db |\n| **HBase** | NoSQL \u8cc7\u6599\u5eab | \u53ef\u4ee5\u5373\u6642\u8b80\u5beb\u7684\u5206\u6563\u5f0f\u8cc7\u6599\u5eab |\n| **Sqoop** | \u8cc7\u6599\u642c\u79fb | \u5728\u50b3\u7d71\u8cc7\u6599\u5eab\u548c Hadoop \u4e4b\u9593\u642c\u8cc7\u6599 |\n| **Flume** | \u65e5\u8a8c\u6536\u96c6 | \u6536\u96c6\u5927\u91cf Log \u8cc7\u6599\u5230 Hadoop |\n| **Zookeeper** | \u5354\u8abf\u670d\u52d9 | \u7ba1\u7406\u5206\u6563\u5f0f\u7cfb\u7d71\u7684\u8a2d\u5b9a\u548c\u540c\u6b65 |\n\n---\n\n## \u4e94\u3001Apache Spark\uff08\u91cd\u8981\uff01\uff09\n\n### Spark vs MapReduce\n\n| \u6bd4\u8f03\u9805\u76ee | MapReduce | Spark |\n|----------|-----------|-------|\n| \u8655\u7406\u901f\u5ea6 | \u6162\uff08\u6bcf\u6b65\u90fd\u5beb\u5165\u786c\u789f\uff09 | **\u5feb 10~100 \u500d**\uff08\u8a18\u61b6\u9ad4\u904b\u7b97\uff09 |\n| \u9069\u7528\u5834\u666f | \u6279\u6b21\u8655\u7406 | \u6279\u6b21 + \u5373\u6642\u4e32\u6d41 + \u6a5f\u5668\u5b78\u7fd2 |\n| \u7a0b\u5f0f\u8a9e\u8a00 | Java \u70ba\u4e3b | Scala, Python, Java, R |\n| \u6613\u7528\u6027 | \u8f03\u8907\u96dc | \u8f03\u7c21\u55ae |\n\n### Spark \u6838\u5fc3\u6982\u5ff5\n- **RDD**\uff08Resilient Distributed Dataset\uff09\uff1a\u5f48\u6027\u5206\u6563\u5f0f\u8cc7\u6599\u96c6\uff0cSpark \u7684\u57fa\u672c\u8cc7\u6599\u55ae\u5143\n- **DataFrame**\uff1a\u985e\u4f3c SQL \u8868\u683c\u7684\u7d50\u69cb\u5316\u8cc7\u6599\uff08\u548c pandas \u7684 DataFrame \u6982\u5ff5\u985e\u4f3c\uff09\n- **Spark SQL**\uff1a\u7528 SQL \u8a9e\u6cd5\u67e5\u8a62 Spark \u8cc7\u6599\n- **Spark Streaming**\uff1a\u5373\u6642\u4e32\u6d41\u8655\u7406\n- **MLlib**\uff1a\u6a5f\u5668\u5b78\u7fd2\u51fd\u5f0f\u5eab\n\n---\n\n## \u516d\u3001ETL \u6d41\u7a0b\uff08\u5fc5\u8003\uff01\uff09\n\n```\n   \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510      \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510      \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n   \u2502 Extract \u2502  \u2192   \u2502  Transform  \u2502  \u2192   \u2502  Load   \u2502\n   \u2502  \u64f7\u53d6   \u2502      \u2502    \u8f49\u63db     \u2502      \u2502  \u8f09\u5165   \u2502\n   \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518      \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518      \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n   \u5f9e\u5404\u7a2e\u4f86\u6e90        \u6e05\u7406\u3001\u6574\u5408\u3001          \u5b58\u5165\u76ee\u6a19\n   \u53d6\u51fa\u539f\u59cb\u8cc7\u6599      \u8f49\u63db\u8cc7\u6599\u683c\u5f0f          \u8cc7\u6599\u5009\u5132\n```\n\n| \u968e\u6bb5 | \u8aaa\u660e | \u7bc4\u4f8b |\n|------|------|------|\n| **E**xtract\uff08\u64f7\u53d6\uff09 | \u5f9e\u5404\u7a2e\u8cc7\u6599\u4f86\u6e90\u53d6\u51fa\u8cc7\u6599 | \u5f9e\u8cc7\u6599\u5eab\u3001API\u3001\u6a94\u6848\u8b80\u53d6\u8cc7\u6599 |\n| **T**ransform\uff08\u8f49\u63db\uff09 | \u6e05\u6d17\u3001\u6574\u7406\u3001\u8f49\u63db\u683c\u5f0f | \u53bb\u9664\u91cd\u8907\u3001\u586b\u88dc\u7a7a\u503c\u3001\u683c\u5f0f\u7d71\u4e00 |\n| **L**oad\uff08\u8f09\u5165\uff09 | \u5c07\u8655\u7406\u597d\u7684\u8cc7\u6599\u5b58\u5165\u76ee\u6a19\u7cfb\u7d71 | \u5b58\u5165\u8cc7\u6599\u5009\u5132\u6216\u8cc7\u6599\u6e56 |\n\n> \ud83d\udca1 **ELT**\uff1a\u5148 Load \u518d Transform\uff0c\u9069\u5408\u96f2\u7aef\u74b0\u5883\uff08\u5982 BigQuery\u3001Snowflake\uff09\n\n---\n\n## \u4e03\u3001\u8cc7\u6599\u5009\u5132 vs \u8cc7\u6599\u6e56\n\n| \u6bd4\u8f03\u9805\u76ee | \u8cc7\u6599\u5009\u5132 (Data Warehouse) | \u8cc7\u6599\u6e56 (Data Lake) |\n|----------|---------------------------|---------------------|\n| **\u8cc7\u6599\u985e\u578b** | \u7d50\u69cb\u5316\u8cc7\u6599 | \u7d50\u69cb\u5316 + \u975e\u7d50\u69cb\u5316 |\n| **\u8655\u7406\u65b9\u5f0f** | \u5148\u6574\u7406\u518d\u5b58\u5165\uff08Schema on Write\uff09 | \u5148\u5b58\u5165\u518d\u6574\u7406\uff08Schema on Read\uff09 |\n| **\u8cc7\u6599\u54c1\u8cea** | \u9ad8\uff08\u5df2\u6e05\u6d17\u6574\u7406\uff09 | \u539f\u59cb\uff08\u672a\u8655\u7406\uff09 |\n| **\u4f7f\u7528\u8005** | \u5546\u696d\u5206\u6790\u5e2b | \u8cc7\u6599\u79d1\u5b78\u5bb6\u3001\u5de5\u7a0b\u5e2b |\n| **\u67e5\u8a62\u901f\u5ea6** | \u5feb | \u770b\u60c5\u6cc1 |\n| **\u6210\u672c** | \u8f03\u9ad8 | \u8f03\u4f4e |\n| **\u4ee3\u8868\u5de5\u5177** | Amazon Redshift, BigQuery | Amazon S3, Azure Data Lake |\n\n> \ud83d\udca1 **\u767d\u8a71\u7248**\uff1a\n> - \u8cc7\u6599\u5009\u5132 = \u6574\u7406\u597d\u7684\u5716\u66f8\u9928\uff08\u66f8\u5df2\u5206\u985e\u4e0a\u67b6\uff09\n> - \u8cc7\u6599\u6e56 = \u4ec0\u9ebc\u90fd\u4e1f\u9032\u53bb\u7684\u5009\u5eab\uff08\u8981\u7528\u6642\u518d\u627e\uff09\n\n---\n\n## \u516b\u3001\u6279\u6b21\u8655\u7406 vs \u4e32\u6d41\u8655\u7406\n\n| \u6bd4\u8f03\u9805\u76ee | \u6279\u6b21\u8655\u7406 (Batch) | \u4e32\u6d41\u8655\u7406 (Streaming) |\n|----------|------------------|----------------------|\n| **\u8655\u7406\u6642\u6a5f** | \u7d2f\u7a4d\u4e00\u6279\u5f8c\u7d71\u4e00\u8655\u7406 | \u8cc7\u6599\u5230\u9054\u5c31\u7acb\u5373\u8655\u7406 |\n| **\u5ef6\u9072** | \u9ad8\uff08\u5206\u9418\u5230\u5c0f\u6642\uff09 | \u4f4e\uff08\u6beb\u79d2\u5230\u79d2\uff09 |\n| **\u9069\u7528\u5834\u666f** | \u6708\u5831\u8868\u3001\u6b77\u53f2\u5206\u6790 | \u5373\u6642\u76e3\u63a7\u3001\u8a50\u9a19\u5075\u6e2c |\n| **\u4ee3\u8868\u5de5\u5177** | MapReduce, Spark Batch | Spark Streaming, Kafka, Flink |\n\n---\n\n## \u4e5d\u3001NoSQL \u8cc7\u6599\u5eab\n\n| \u985e\u578b | \u8aaa\u660e | \u4ee3\u8868\u5de5\u5177 |\n|------|------|----------|\n| **Key-Value** | \u9375\u503c\u5c0d\uff0c\u6700\u7c21\u55ae | Redis, DynamoDB |\n| **Document** | \u6587\u4ef6\u578b\uff08JSON\uff09 | MongoDB, CouchDB |\n| **Column-Family** | \u5217\u65cf\u578b | HBase, Cassandra |\n| **Graph** | \u5716\u5f62\u578b\uff08\u7bc0\u9ede+\u95dc\u4fc2\uff09 | Neo4j |\n\n### SQL vs NoSQL\n\n| \u6bd4\u8f03 | SQL\uff08\u95dc\u806f\u5f0f\uff09 | NoSQL\uff08\u975e\u95dc\u806f\u5f0f\uff09 |\n|------|---------------|-------------------|\n| \u7d50\u69cb | \u56fa\u5b9a\u8868\u683c\u7d50\u69cb | \u9748\u6d3b\u7d50\u69cb |\n| \u64f4\u5c55 | \u5782\u76f4\u64f4\u5c55\uff08\u52a0\u5f37\u55ae\u6a5f\uff09 | \u6c34\u5e73\u64f4\u5c55\uff08\u52a0\u66f4\u591a\u6a5f\u5668\uff09 |\n| \u4ea4\u6613 | \u652f\u63f4 ACID | \u90e8\u5206\u652f\u63f4 |\n| \u9069\u7528 | \u7d50\u69cb\u5316\u8cc7\u6599\u3001\u8907\u96dc\u67e5\u8a62 | \u5927\u91cf\u975e\u7d50\u69cb\u5316\u8cc7\u6599 |\n\n---\n\n## \u5341\u3001\u5e38\u898b\u96f2\u7aef\u5927\u6578\u64da\u670d\u52d9\n\n| \u96f2\u7aef\u5e73\u53f0 | \u670d\u52d9 | \u5c0d\u61c9\u529f\u80fd |\n|----------|------|----------|\n| **Google** | BigQuery | \u8cc7\u6599\u5009\u5132 |\n| **AWS** | Redshift | \u8cc7\u6599\u5009\u5132 |\n| **AWS** | S3 | \u8cc7\u6599\u6e56 / \u7269\u4ef6\u5132\u5b58 |\n| **Azure** | Synapse | \u8cc7\u6599\u5009\u5132 |\n| **Google** | Dataflow | \u4e32\u6d41 + \u6279\u6b21\u8655\u7406 |\n\n---\n\n## \u5e38\u898b\u8003\u984c\u901f\u8a18\n\n| \u984c\u578b | \u7b54\u6848\u95dc\u9375\u5b57 |\n|------|-----------|\n| \u5927\u6578\u64da\u7279\u6027 | 5V\uff1aVolume, Velocity, Variety, Veracity, Value |\n| HDFS \u7279\u9ede | \u5206\u6563\u5f0f\u3001\u9ad8\u5bb9\u932f\u3001\u9069\u5408\u5927\u6a94\u6848 |\n| MapReduce \u6b65\u9a5f | Map \u2192 Shuffle \u2192 Reduce |\n| Spark \u6bd4 MapReduce \u5feb\u7684\u539f\u56e0 | \u8a18\u61b6\u9ad4\u904b\u7b97\uff08In-memory\uff09 |\n| ETL \u662f\u4ec0\u9ebc | Extract \u2192 Transform \u2192 Load |\n| \u8cc7\u6599\u5009\u5132 vs \u8cc7\u6599\u6e56 | \u7d50\u69cb\u5316 vs \u5168\u985e\u578b\u3001Schema on Write vs Read |\n\n---\n\n*\ud83d\udcdd by \u751c\u8766 \ud83c\udf64 | 2026.04.20*\n", "03_Python.md": "# \ud83d\udc0d Python \u7a0b\u5f0f\u8a9e\u8a00 \u2014 \u8003\u8a66\u91cd\u9ede\u7b46\u8a18\n> \u4f54\u6bd4\uff1a**20%** \uff5c \u512a\u5148\u5ea6\uff1a\u2b50\u2b50\n\n---\n\n## \u4e00\u3001\u57fa\u672c\u8a9e\u6cd5\n\n### \u8b8a\u6578\u8207\u8cc7\u6599\u578b\u5225\n```python\n# \u6578\u503c\nage = 25              # int\uff08\u6574\u6578\uff09\nheight = 170.5        # float\uff08\u6d6e\u9ede\u6578\uff09\n\n# \u5b57\u4e32\nname = \"Ann\"          # str\uff08\u5b57\u4e32\uff09\n\n# \u5e03\u6797\nis_student = True     # bool\uff08\u5e03\u6797\u503c\uff1aTrue / False\uff09\n\n# \u67e5\u770b\u578b\u5225\nprint(type(age))      # <class 'int'>\n```\n\n### \u578b\u5225\u8f49\u63db\n```python\nint(\"123\")       # \u5b57\u4e32 \u2192 \u6574\u6578 = 123\nfloat(\"3.14\")    # \u5b57\u4e32 \u2192 \u6d6e\u9ede\u6578 = 3.14\nstr(100)         # \u6574\u6578 \u2192 \u5b57\u4e32 = \"100\"\nbool(0)          # 0 \u2192 False\uff0c\u5176\u4ed6\u6578\u5b57 \u2192 True\n```\n\n---\n\n## \u4e8c\u3001\u904b\u7b97\u5b50\n\n| \u985e\u578b | \u904b\u7b97\u5b50 | \u7bc4\u4f8b |\n|------|--------|------|\n| \u7b97\u8853 | `+`, `-`, `*`, `/`, `//`, `%`, `**` | `7 // 2 = 3`\uff08\u6574\u9664\uff09\u3001`2**3 = 8`\uff08\u6b21\u65b9\uff09 |\n| \u6bd4\u8f03 | `==`, `!=`, `>`, `<`, `>=`, `<=` | `5 == 5` \u2192 `True` |\n| \u908f\u8f2f | `and`, `or`, `not` | `True and False` \u2192 `False` |\n| \u6210\u54e1 | `in`, `not in` | `\"a\" in \"apple\"` \u2192 `True` |\n\n> \u26a0\ufe0f Python \u7528 `==` \u6bd4\u8f03\u503c\uff0c\u7528 `is` \u6bd4\u8f03\u8a18\u61b6\u9ad4\u4f4d\u7f6e\n\n---\n\n## \u4e09\u3001\u6d41\u7a0b\u63a7\u5236\n\n### if / elif / else\n```python\nscore = 85\n\nif score >= 90:\n    print(\"A\")\nelif score >= 80:\n    print(\"B\")       # \u2190 \u8f38\u51fa B\nelif score >= 70:\n    print(\"C\")\nelse:\n    print(\"F\")\n```\n\n### for \u8ff4\u5708\n```python\n# \u904d\u6b77\u5217\u8868\nfruits = [\"\u860b\u679c\", \"\u9999\u8549\", \"\u6a58\u5b50\"]\nfor fruit in fruits:\n    print(fruit)\n\n# \u4f7f\u7528 range\nfor i in range(5):        # 0, 1, 2, 3, 4\n    print(i)\n\nfor i in range(1, 6):     # 1, 2, 3, 4, 5\n    print(i)\n\nfor i in range(0, 10, 2): # 0, 2, 4, 6, 8\uff08\u6b65\u9577 2\uff09\n    print(i)\n```\n\n### while \u8ff4\u5708\n```python\ncount = 0\nwhile count < 5:\n    print(count)\n    count += 1\n```\n\n### break \u8207 continue\n```python\nfor i in range(10):\n    if i == 3:\n        continue    # \u8df3\u904e\u672c\u6b21\uff0c\u7e7c\u7e8c\u4e0b\u4e00\u6b21\n    if i == 7:\n        break       # \u76f4\u63a5\u7d50\u675f\u6574\u500b\u8ff4\u5708\n    print(i)        # \u8f38\u51fa\uff1a0, 1, 2, 4, 5, 6\n```\n\n---\n\n## \u56db\u3001\u8cc7\u6599\u7d50\u69cb\uff08\u5fc5\u8003\uff01\uff09\n\n### List\uff08\u5217\u8868\uff09\u2014 \u6709\u5e8f\u3001\u53ef\u4fee\u6539\u3001\u53ef\u91cd\u8907\n```python\nfruits = [\"\u860b\u679c\", \"\u9999\u8549\", \"\u6a58\u5b50\"]\nfruits.append(\"\u897f\u74dc\")       # \u65b0\u589e\u5143\u7d20\nfruits.remove(\"\u9999\u8549\")       # \u79fb\u9664\u5143\u7d20\nfruits[0]                    # \u53d6\u5f97\u7b2c\u4e00\u500b\u5143\u7d20 = \"\u860b\u679c\"\nfruits[-1]                   # \u53d6\u5f97\u6700\u5f8c\u4e00\u500b\u5143\u7d20\nlen(fruits)                  # \u9577\u5ea6\nfruits.sort()                # \u6392\u5e8f\n```\n\n### Tuple\uff08\u5143\u7d44\uff09\u2014 \u6709\u5e8f\u3001\u4e0d\u53ef\u4fee\u6539\n```python\npoint = (3, 5)\nx = point[0]     # \u53ef\u4ee5\u8b80\u53d6\n# point[0] = 10  # \u274c \u932f\u8aa4\uff01\u4e0d\u80fd\u4fee\u6539\n```\n\n### Dict\uff08\u5b57\u5178\uff09\u2014 \u9375\u503c\u5c0d\u3001\u7121\u5e8f\n```python\nstudent = {\n    \"name\": \"Ann\",\n    \"age\": 25,\n    \"city\": \"\u53f0\u5317\"\n}\nstudent[\"name\"]              # \"Ann\"\nstudent[\"email\"] = \"ann@x\"   # \u65b0\u589e\nstudent.keys()               # \u6240\u6709\u9375\nstudent.values()             # \u6240\u6709\u503c\nstudent.items()              # \u6240\u6709\u9375\u503c\u5c0d\n```\n\n### Set\uff08\u96c6\u5408\uff09\u2014 \u7121\u5e8f\u3001\u4e0d\u91cd\u8907\n```python\na = {1, 2, 3, 4}\nb = {3, 4, 5, 6}\na | b    # \u806f\u96c6 {1, 2, 3, 4, 5, 6}\na & b    # \u4ea4\u96c6 {3, 4}\na - b    # \u5dee\u96c6 {1, 2}\n```\n\n### \u56db\u5927\u8cc7\u6599\u7d50\u69cb\u6bd4\u8f03\n\n| \u7279\u6027 | List | Tuple | Dict | Set |\n|------|------|-------|------|-----|\n| \u7b26\u865f | `[]` | `()` | `{}` | `{}` |\n| \u6709\u5e8f | \u2705 | \u2705 | \u274c | \u274c |\n| \u53ef\u4fee\u6539 | \u2705 | \u274c | \u2705 | \u2705 |\n| \u53ef\u91cd\u8907 | \u2705 | \u2705 | \u9375\u4e0d\u53ef | \u274c |\n| \u7d22\u5f15\u5b58\u53d6 | \u2705 | \u2705 | \u7528\u9375 | \u274c |\n\n---\n\n## \u4e94\u3001\u51fd\u6578\uff08Function\uff09\n\n### \u5b9a\u7fa9\u8207\u547c\u53eb\n```python\ndef greet(name, greeting=\"\u4f60\u597d\"):\n    \"\"\"\u9019\u662f\u4e00\u500b\u6253\u62db\u547c\u7684\u51fd\u6578\"\"\"\n    return f\"{greeting}, {name}!\"\n\nresult = greet(\"Ann\")           # \"\u4f60\u597d, Ann!\"\nresult = greet(\"Ann\", \"\u55e8\")     # \"\u55e8, Ann!\"\n```\n\n### *args \u8207 **kwargs\n```python\ndef total(*args):           # \u63a5\u6536\u4efb\u610f\u6578\u91cf\u7684\u53c3\u6578\n    return sum(args)\n\ntotal(1, 2, 3)              # 6\n\ndef info(**kwargs):          # \u63a5\u6536\u4efb\u610f\u6578\u91cf\u7684\u95dc\u9375\u5b57\u53c3\u6578\n    for k, v in kwargs.items():\n        print(f\"{k}: {v}\")\n\ninfo(name=\"Ann\", age=25)\n```\n\n### Lambda \u533f\u540d\u51fd\u6578\n```python\nsquare = lambda x: x ** 2\nsquare(5)   # 25\n\n# \u5e38\u642d\u914d map, filter \u4f7f\u7528\nnumbers = [1, 2, 3, 4, 5]\nsquared = list(map(lambda x: x**2, numbers))   # [1, 4, 9, 16, 25]\nevens = list(filter(lambda x: x%2==0, numbers)) # [2, 4]\n```\n\n---\n\n## \u516d\u3001List Comprehension\uff08\u5217\u8868\u63a8\u5c0e\u5f0f\uff09\n\n```python\n# \u50b3\u7d71\u5beb\u6cd5\nsquares = []\nfor x in range(10):\n    squares.append(x**2)\n\n# \u63a8\u5c0e\u5f0f\uff08\u4e00\u884c\u641e\u5b9a\uff09\nsquares = [x**2 for x in range(10)]\n\n# \u5e36\u689d\u4ef6\nevens = [x for x in range(20) if x % 2 == 0]\n```\n\n---\n\n## \u4e03\u3001\u6a94\u6848\u8b80\u5beb\n\n```python\n# \u5beb\u5165\u6a94\u6848\nwith open(\"output.txt\", \"w\", encoding=\"utf-8\") as f:\n    f.write(\"Hello, Ann!\\n\")\n\n# \u8b80\u53d6\u6a94\u6848\nwith open(\"output.txt\", \"r\", encoding=\"utf-8\") as f:\n    content = f.read()        # \u8b80\u5168\u90e8\n    # lines = f.readlines()   # \u8b80\u6210\u5217\u8868\uff08\u4e00\u884c\u4e00\u500b\u5143\u7d20\uff09\n```\n\n> \ud83d\udca1 **`with` \u8a9e\u6cd5**\uff1a\u6703\u81ea\u52d5\u95dc\u9589\u6a94\u6848\uff0c\u4e0d\u9700\u8981\u624b\u52d5 `f.close()`\n\n### \u6a21\u5f0f\n| \u6a21\u5f0f | \u8aaa\u660e |\n|------|------|\n| `\"r\"` | \u8b80\u53d6\uff08\u9810\u8a2d\uff09 |\n| `\"w\"` | \u5beb\u5165\uff08\u8986\u84cb\uff09 |\n| `\"a\"` | \u9644\u52a0\uff08\u4e0d\u8986\u84cb\uff09 |\n| `\"rb\"` | \u8b80\u53d6\u4e8c\u9032\u4f4d\u6a94\u6848 |\n\n---\n\n## \u516b\u3001\u4f8b\u5916\u8655\u7406\n\n```python\ntry:\n    result = 10 / 0\nexcept ZeroDivisionError:\n    print(\"\u4e0d\u80fd\u9664\u4ee5\u96f6\uff01\")\nexcept Exception as e:\n    print(f\"\u767c\u751f\u932f\u8aa4\uff1a{e}\")\nfinally:\n    print(\"\u4e0d\u7ba1\u6709\u6c92\u6709\u932f\u8aa4\u90fd\u6703\u57f7\u884c\")\n```\n\n---\n\n## \u4e5d\u3001\u5e38\u7528\u5957\u4ef6\n\n### pandas \u2014 \u8cc7\u6599\u5206\u6790\u795e\u5668\n```python\nimport pandas as pd\n\n# \u5efa\u7acb DataFrame\ndf = pd.DataFrame({\n    \"\u59d3\u540d\": [\"Ann\", \"Bob\", \"Carol\"],\n    \"\u5206\u6578\": [90, 75, 85],\n    \"\u57ce\u5e02\": [\"\u53f0\u5317\", \"\u9ad8\u96c4\", \"\u53f0\u5317\"]\n})\n\n# \u57fa\u672c\u64cd\u4f5c\ndf.head()                # \u524d 5 \u7b46\ndf.shape                 # (3, 3) = 3\u52173\u6b04\ndf.describe()            # \u7d71\u8a08\u6458\u8981\ndf[\"\u5206\u6578\"].mean()        # \u5e73\u5747\u5206\u6578\ndf[df[\"\u5206\u6578\"] > 80]      # \u7be9\u9078\u5206\u6578 > 80\n\n# \u8b80\u53d6 CSV\ndf = pd.read_csv(\"data.csv\")\ndf.to_csv(\"output.csv\", index=False)\n```\n\n### matplotlib \u2014 \u7e6a\u5716\n```python\nimport matplotlib.pyplot as plt\n\nx = [1, 2, 3, 4, 5]\ny = [10, 20, 15, 25, 30]\n\nplt.plot(x, y)\nplt.title(\"Sales Chart\")\nplt.xlabel(\"Month\")\nplt.ylabel(\"Revenue\")\nplt.show()\n```\n\n---\n\n## \u5341\u3001\u5e38\u898b\u8003\u984c\u901f\u8a18\n\n| \u984c\u578b | \u91cd\u9ede |\n|------|------|\n| `list` vs `tuple` | list \u53ef\u6539\u3001tuple \u4e0d\u53ef\u6539 |\n| `==` vs `is` | `==` \u6bd4\u503c\u3001`is` \u6bd4\u8a18\u61b6\u9ad4\u4f4d\u7f6e |\n| `range(5)` \u7522\u751f\u4ec0\u9ebc | 0, 1, 2, 3, 4\uff08\u4e0d\u5305\u542b 5\uff09 |\n| \u5b57\u5178\u53d6\u503c | `dict[\"key\"]` \u6216 `dict.get(\"key\", default)` |\n| `with open` \u7684\u597d\u8655 | \u81ea\u52d5\u95dc\u9589\u6a94\u6848 |\n| lambda \u662f\u4ec0\u9ebc | \u4e00\u884c\u7684\u533f\u540d\u51fd\u6578 |\n| pandas \u8b80 CSV | `pd.read_csv(\"file.csv\")` |\n\n---\n\n*\ud83d\udcdd by \u751c\u8766 \ud83c\udf64 | 2026.04.20*\n", "04_AI_Integration.md": "# \ud83e\udd16 AI \u6574\u5408\u61c9\u7528 (Agent/MCP/Tools/Skills) \u2014 \u8003\u8a66\u91cd\u9ede\u7b46\u8a18\n> \u4f54\u6bd4\uff1a**15%** \uff5c \u512a\u5148\u5ea6\uff1a\u2b50\n\n---\n\n## \u4e00\u3001AI Agent\uff08\u4eba\u5de5\u667a\u6167\u4ee3\u7406\uff09\n\n### \u4ec0\u9ebc\u662f AI Agent\uff1f\n\u50b3\u7d71\u7684 AI\uff08\u5982\u65e9\u671f\u7684 ChatGPT\uff09\u53ea\u80fd\u300c\u4f60\u554f\u6211\u7b54\u300d\u3002\n**AI Agent** \u5247\u662f\u5177\u5099\u300c**\u81ea\u4e3b\u6027**\u300d\u7684\u7cfb\u7d71\uff0c\u5b83\u4e0d\u50c5\u80fd\u5c0d\u8a71\uff0c\u9084\u80fd**\u611f\u77e5\u74b0\u5883\u3001\u601d\u8003\u898f\u5283\u3001\u4e26\u63a1\u53d6\u884c\u52d5**\u4f86\u5b8c\u6210\u8907\u96dc\u4efb\u52d9\u3002\n\n### Agent \u7684\u4e09\u5927\u6838\u5fc3\u80fd\u529b\uff08\u904b\u4f5c\u67b6\u69cb\uff09\n| \u6838\u5fc3 | \u82f1\u6587 | \u8aaa\u660e |\n|------|------|------|\n| **\u611f\u77e5** | Perception | \u63a5\u6536\u8f38\u5165\uff0c\u4f8b\u5982\uff1a\u8b80\u53d6\u4f7f\u7528\u8005\u7684\u8a0a\u606f\u3001\u67e5\u770b\u76ee\u524d\u958b\u555f\u7684\u6a94\u6848\u3001\u4e86\u89e3\u96fb\u8166\u72c0\u614b\u3002 |\n| **\u601d\u8003/\u898f\u5283** | Planning / Brain | \u5206\u6790\u4efb\u52d9\u3001\u62c6\u89e3\u6b65\u9a5f\u3001\u6c7a\u5b9a\u9700\u8981\u547c\u53eb\u4ec0\u9ebc\u5de5\u5177\u3001\u601d\u8003\u89e3\u6c7a\u65b9\u6848\u3002 |\n| **\u884c\u52d5** | Action | \u547c\u53eb\u5916\u90e8\u5de5\u5177\uff08\u5982\u57f7\u884c\u7a0b\u5f0f\u78bc\u3001\u5beb\u5165\u6a94\u6848\u3001\u641c\u5c0b\u7db2\u8def\uff09\u4f86\u6539\u8b8a\u74b0\u5883\u3002 |\n\n> \ud83d\udca1 **\u751c\u8766\u6bd4\u55bb**\uff1a\n> - \u50b3\u7d71 AI \u662f\u4e00\u672c\u767e\u79d1\u5168\u66f8\uff08\u53ea\u80fd\u67e5\u8cc7\u6599\uff09\u3002\n> - AI Agent \u662f\u4e00\u500b\u5be6\u7fd2\u751f\uff08\u4f60\u7d66\u4ed6\u4efb\u52d9\uff0c\u4ed6\u6703\u81ea\u5df1\u898f\u5283\u6b65\u9a5f\u4e26\u53bb\u57f7\u884c\uff09\u3002\n\n---\n\n## \u4e8c\u3001MCP (Model Context Protocol) \u6a21\u578b\u4e0a\u4e0b\u6587\u5354\u5b9a\n\n### \u4ec0\u9ebc\u662f MCP\uff1f\nMCP \u662f\u4e00\u7a2e**\u6a19\u6e96\u5316\u901a\u8a0a\u5354\u5b9a**\u3002\u5b83\u5b9a\u7fa9\u4e86 AI \u6a21\u578b\uff08Model\uff09\u5982\u4f55\u8207\u5916\u90e8\u8cc7\u6599\u4f86\u6e90\u6216\u5de5\u5177\uff08Context\uff09\u9032\u884c\u5b89\u5168\u3001\u7d71\u4e00\u7684\u6e9d\u901a\u3002\n\n### \u70ba\u4ec0\u9ebc\u9700\u8981 MCP\uff1f\n\u4ee5\u524d\uff0c\u6bcf\u500b AI \u61c9\u7528\u5982\u679c\u8981\u9023\u63a5\u672c\u5730\u6a94\u6848\u3001GitHub \u6216\u8cc7\u6599\u5eab\uff0c\u90fd\u9700\u8981\u5beb\u5ba2\u88fd\u5316\u7684\u6574\u5408\u7a0b\u5f0f\u78bc\u3002\nMCP \u63d0\u4f9b\u4e86\u4e00\u500b\u6a19\u6e96\u4ecb\u9762\uff0c\u8b93 AI \u53ef\u4ee5**\u96a8\u63d2\u5373\u7528**\u5730\u5b58\u53d6\u5404\u7a2e\u5916\u90e8\u8cc7\u6e90\uff0c\u5c31\u50cf USB \u96a8\u8eab\u789f\u4e00\u6a23\uff0c\u63d2\u4e0a\u53bb\u5c31\u80fd\u8b80\u53d6\u8cc7\u6599\u3002\n\n### MCP \u7684\u67b6\u69cb\n- **MCP Client\uff08\u5ba2\u6236\u7aef\uff09**\uff1a\u4f8b\u5982 Claude Desktop\u3001Antigravity\uff0c\u662f\u767c\u8d77\u8acb\u6c42\u7684\u4e00\u65b9\u3002\n- **MCP Server\uff08\u4f3a\u670d\u5668\u7aef\uff09**\uff1a\u63d0\u4f9b\u8cc7\u6e90\u6216\u5de5\u5177\u7684\u4e00\u65b9\uff08\u4f8b\u5982\uff1a\u4e00\u500b\u5c08\u9580\u8b80\u53d6 Google Drive \u7684 MCP Server\uff09\u3002\n- **Protocol\uff08\u5354\u5b9a\uff09**\uff1a\u5169\u8005\u4e4b\u9593\u900f\u904e\u6a19\u6e96\u5316\u7684 JSON \u683c\u5f0f\u4ea4\u63db\u8a0a\u606f\u3002\n\n---\n\n## \u4e09\u3001Tools\uff08\u5de5\u5177\uff09\u8207 Function Calling\uff08\u51fd\u6578\u547c\u53eb\uff09\n\n### \u4ec0\u9ebc\u662f Tools\uff1f\nAI \u672c\u8eab\u53ea\u662f\u4e00\u500b\u300c\u5927\u8166\u300d\uff0c\u6c92\u6709\u624b\u8173\u3002**Tools\uff08\u5de5\u5177\uff09\u5c31\u662f AI \u7684\u624b\u8173**\u3002\u900f\u904e\u5de5\u5177\uff0cAI \u53ef\u4ee5\u8207\u5916\u90e8\u4e16\u754c\u4e92\u52d5\u3002\n\n### \u5e38\u898b\u7684 Tools \u7bc4\u4f8b\n- **\u6a94\u6848\u64cd\u4f5c**\uff1a`read_file`, `write_to_file`, `list_directory`\n- **\u7d42\u7aef\u6a5f/\u547d\u4ee4\u5217**\uff1a`run_command`\uff08\u8b93 AI \u80fd\u57f7\u884c PowerShell \u6307\u4ee4\uff09\n- **\u7db2\u8def\u5b58\u53d6**\uff1a`search_web`, `read_url`\n- **\u7a0b\u5f0f\u57f7\u884c**\uff1a\u8b93 AI \u57f7\u884c Python \u8173\u672c\u4e26\u7372\u53d6\u7d50\u679c\n\n### Function Calling \u7684\u904b\u4f5c\u6d41\u7a0b\uff08\u5fc5\u8003\uff01\uff09\n1. **\u5ba3\u544a\uff08Declaration\uff09**\uff1a\u7cfb\u7d71\u9810\u5148\u544a\u8a34 AI \u6709\u54ea\u4e9b\u51fd\u6578\uff08Tools\uff09\u53ef\u7528\uff0c\u4ee5\u53ca\u6bcf\u500b\u51fd\u6578\u7684\u53c3\u6578\u683c\u5f0f\u3002\n2. **\u6c7a\u7b56\uff08Decision\uff09**\uff1aAI \u6536\u5230\u4f7f\u7528\u8005\u8acb\u6c42\u5f8c\uff0c\u5224\u65b7\u662f\u5426\u9700\u8981\u547c\u53eb\u51fd\u6578\u3002\n3. **\u547c\u53eb\uff08Tool Call\uff09**\uff1aAI \u8f38\u51fa\u7279\u5b9a\u683c\u5f0f\uff08\u5982 JSON\uff09\uff0c\u8981\u6c42\u7cfb\u7d71\u57f7\u884c\u8a72\u51fd\u6578\uff0c\u4e26\u63d0\u4f9b\u5fc5\u8981\u53c3\u6578\u3002\n4. **\u57f7\u884c\uff08Execution\uff09**\uff1a\u7cfb\u7d71\u5728\u80cc\u666f\u57f7\u884c\u51fd\u6578\u3002\n5. **\u56de\u50b3\uff08Response\uff09**\uff1a\u7cfb\u7d71\u5c07\u51fd\u6578\u57f7\u884c\u7684\u7d50\u679c\uff08Tool Response\uff09\u50b3\u56de\u7d66 AI\u3002\n6. **\u7e3d\u7d50\uff08Final Output\uff09**\uff1aAI \u6839\u64da\u7d50\u679c\u751f\u6210\u6700\u7d42\u56de\u7b54\u7d66\u4f7f\u7528\u8005\u3002\n\n---\n\n## \u56db\u3001Skills\uff08\u6280\u80fd\uff09\n\n### \u4ec0\u9ebc\u662f Skills\uff1f\nSkills \u662f\u4e00\u7a2e**\u53ef\u91cd\u8907\u4f7f\u7528\u7684\u77e5\u8b58\u6216\u6d41\u7a0b\u6a21\u7d44**\u3002\u5b83\u628a\u89e3\u6c7a\u7279\u5b9a\u554f\u984c\u7684\u7d93\u9a57\u8a18\u9304\u4e0b\u4f86\uff0c\u8b93 AI \u4e0b\u6b21\u9047\u5230\u985e\u4f3c\u4efb\u52d9\u6642\uff0c\u53ef\u4ee5\u76f4\u63a5\u8abf\u7528\uff0c\u800c\u4e0d\u7528\u5f9e\u96f6\u958b\u59cb\u6478\u7d22\u3002\n\n### Skills \u7684\u597d\u8655\n- **\u6e1b\u5c11\u91cd\u8907\u8a66\u932f**\uff1a\u907f\u514d\u6bcf\u6b21\u90fd\u8e29\u4e00\u6a23\u7684\u5751\uff08\u4f8b\u5982\uff1a\u4e00\u76f4\u88ab Cloudflare \u64cb\uff09\u3002\n- **\u500b\u4eba\u5316**\uff1a\u8a18\u9304\u4f7f\u7528\u8005\u7684\u7279\u5b9a\u504f\u597d\u6216\u5c08\u6848\u7684\u7279\u5b9a\u67b6\u69cb\u3002\n- **\u63d0\u5347\u6548\u7387**\uff1a\u8b93 AI \u80fd\u5feb\u901f\u9032\u5165\u72c0\u6cc1\uff0c\u76f4\u63a5\u7d66\u51fa\u6700\u4f73\u89e3\u6cd5\u3002\n\n> \ud83d\udca1 **\u5c31\u50cf\u662f\u7d66 AI \u5403\u7684\u300c\u8a18\u61b6\u5410\u53f8\u300d\u6216\u300c\u64cd\u4f5c\u624b\u518a\u300d**\u3002\n\n---\n\n## \u4e94\u3001Prompt Engineering \u57fa\u790e\uff08\u63d0\u793a\u8a5e\u5de5\u7a0b\uff09\n\n### \u5beb\u597d Prompt \u7684\u539f\u5247\n1. **\u660e\u78ba\u5177\u9ad4**\uff1a\u907f\u514d\u6a21\u7cca\u4e0d\u6e05\u7684\u6307\u4ee4\u3002\n2. **\u63d0\u4f9b\u4e0a\u4e0b\u6587**\uff1a\u7d66\u4e88 AI \u5145\u8db3\u7684\u80cc\u666f\u8cc7\u8a0a\uff08Context\uff09\u3002\n3. **\u6307\u5b9a\u89d2\u8272/\u8a9e\u6c23**\uff1a\u4f8b\u5982\u300c\u4f60\u662f\u4e00\u4f4d\u5c08\u696d\u7684\u8cc7\u6599\u79d1\u5b78\u5bb6...\u300d\u3002\n4. **\u7d66\u4e88\u7bc4\u4f8b\uff08Few-shot prompting\uff09**\uff1a\u63d0\u4f9b\u8f38\u5165\u8f38\u51fa\u7684\u7bc4\u4f8b\uff0c\u8b93 AI \u7167\u8457\u505a\u3002\n5. **\u6307\u5b9a\u8f38\u51fa\u683c\u5f0f**\uff1a\u8981\u6c42\u4ee5 Markdown\u3001JSON\u3001\u8868\u683c\u7b49\u7279\u5b9a\u683c\u5f0f\u8f38\u51fa\u3002\n\n### RAG (Retrieval-Augmented Generation) \u6aa2\u7d22\u589e\u5f37\u751f\u6210\n- **\u5b9a\u7fa9**\uff1a\u5728\u8b93 AI \u56de\u7b54\u554f\u984c\u4e4b\u524d\uff0c\u5148\u53bb\u5916\u90e8\u8cc7\u6599\u5eab\uff08\u5982\u4f01\u696d\u5167\u90e8\u6587\u4ef6\uff09**\u6aa2\u7d22\uff08Retrieve\uff09** \u76f8\u95dc\u8cc7\u8a0a\uff0c\u628a\u9019\u4e9b\u8cc7\u8a0a\u52a0\u5165 Prompt \u4e2d\uff08Augmented\uff09\uff0c\u518d\u8b93 AI **\u751f\u6210\uff08Generate\uff09** \u56de\u7b54\u3002\n- **\u76ee\u7684**\uff1a\u89e3\u6c7a AI \u5e7b\u89ba\uff08\u80e1\u8aaa\u516b\u9053\uff09\u7684\u554f\u984c\uff0c\u8b93 AI \u80fd\u6839\u64da\u6700\u65b0\u3001\u6700\u6e96\u78ba\u7684\u5167\u90e8\u8cc7\u6599\u56de\u7b54\u3002\n\n---\n\n## \u5e38\u898b\u8003\u984c\u901f\u8a18\n\n| \u984c\u578b\u95dc\u9375\u5b57 | \u5c0d\u61c9\u6982\u5ff5 |\n|------------|----------|\n| \u5177\u5099\u81ea\u4e3b\u898f\u5283\u8207\u57f7\u884c\u4efb\u52d9\u80fd\u529b\u7684\u7cfb\u7d71 | AI Agent |\n| \u6a19\u6e96\u5316 AI \u8207\u5916\u90e8\u8cc7\u6599\u6e9d\u901a\u7684\u5354\u5b9a | MCP (Model Context Protocol) |\n| \u8b93 AI \u80fd\u5920\u57f7\u884c\u5916\u90e8\u7a0b\u5f0f\u6216\u8b80\u5beb\u6a94\u6848\u7684\u6a5f\u5236 | Tools / Function Calling |\n| \u5c07\u89e3\u6c7a\u554f\u984c\u7684\u7d93\u9a57\u8207\u6d41\u7a0b\u8a18\u9304\u4e0b\u4f86\u4f9b AI \u91cd\u8907\u4f7f\u7528 | Skills |\n| \u89e3\u6c7a AI \u5e7b\u89ba\uff0c\u7d50\u5408\u5916\u90e8\u77e5\u8b58\u5eab\u7684\u6280\u8853 | RAG (\u6aa2\u7d22\u589e\u5f37\u751f\u6210) |\n| Agent \u7684\u4e09\u5927\u6838\u5fc3\u6b65\u9a5f | \u611f\u77e5 (Perception) \u2192 \u601d\u8003 (Planning) \u2192 \u884c\u52d5 (Action) |\n\n---\n\n*\ud83d\udcdd by \u751c\u8766 \ud83c\udf64 | 2026.04.20*\n", "05_DataModel.md": "# \ud83d\udcca \u8cc7\u6599\u6a21\u578b (Data Model) \u2014 \u8003\u8a66\u91cd\u9ede\u7b46\u8a18\n> \u4f54\u6bd4\uff1a**15%** \uff5c \u512a\u5148\u5ea6\uff1a\u2b50\n\n---\n\n## \u4e00\u3001\u4ec0\u9ebc\u662f\u8cc7\u6599\u6a21\u578b\uff1f\n\n\u8cc7\u6599\u6a21\u578b\uff08Data Model\uff09\u662f**\u5c0d\u73fe\u5be6\u4e16\u754c\u4e2d\u8cc7\u6599\u7684\u62bd\u8c61\u5316\u63cf\u8ff0**\uff0c\u7528\u4f86\u5b9a\u7fa9\u8cc7\u6599\u7684\u7d50\u69cb\u3001\u95dc\u4fc2\u4ee5\u53ca\u7d04\u675f\u689d\u4ef6\u3002\n\u5b83\u5c31\u50cf\u662f\u8cc7\u6599\u5eab\u7684\u300c\u5efa\u7bc9\u85cd\u5716\u300d\uff0c\u5728\u5be6\u969b\u5efa\u7acb\u8868\u683c\u4e4b\u524d\uff0c\u5fc5\u9808\u5148\u8a2d\u8a08\u597d\u8cc7\u6599\u6a21\u578b\u3002\n\n### \u8cc7\u6599\u5efa\u6a21\u7684\u4e09\u500b\u968e\u6bb5\uff08\u7531\u62bd\u8c61\u5230\u5177\u9ad4\uff09\n1. **\u6982\u5ff5\u6a21\u578b (Conceptual Model)**\uff1a\u7d66\u696d\u52d9\u4eba\u54e1\u770b\uff0c\u5b9a\u7fa9\u4e3b\u8981\u5be6\u9ad4\u548c\u4ed6\u5011\u4e4b\u9593\u7684\u95dc\u4fc2\uff08\u5982\uff1a\u9867\u5ba2\u3001\u8a02\u55ae\u3001\u7522\u54c1\uff09\u3002\u4e0d\u6d89\u53ca\u5177\u9ad4\u6280\u8853\u7d30\u7bc0\u3002\n2. **\u908f\u8f2f\u6a21\u578b (Logical Model)**\uff1a\u7d66\u7cfb\u7d71\u5206\u6790\u5e2b\u770b\uff0c\u5b9a\u7fa9\u5c6c\u6027\u3001\u4e3b\u9375\u3001\u5916\u9375\uff08\u5982\uff1a\u9867\u5ba2\u8868\u6709\u9867\u5ba2ID\u3001\u59d3\u540d\u3001\u96fb\u8a71\uff09\u3002\n3. **\u5be6\u9ad4\u6a21\u578b (Physical Model)**\uff1a\u7d66 DBA \u6216\u5de5\u7a0b\u5e2b\u770b\uff0c\u5b9a\u7fa9\u5177\u9ad4\u7684\u8cc7\u6599\u5eab\u7d50\u69cb\uff08\u5982\uff1a\u4f7f\u7528 MySQL\uff0c\u9867\u5ba2ID \u662f INT\uff0c\u59d3\u540d\u662f VARCHAR(50)\uff09\u3002\n\n---\n\n## \u4e8c\u3001ER \u6a21\u578b (Entity-Relationship Model)\n\nER \u6a21\u578b\u662f\u7528\u4f86\u7e6a\u88fd**\u6982\u5ff5\u6a21\u578b**\u6700\u5e38\u898b\u7684\u5de5\u5177\u3002\n\n### \u4e09\u5927\u6838\u5fc3\u5143\u7d20\n| \u5143\u7d20 | \u82f1\u6587 | \u8aaa\u660e | \u5716\u5f62\u8868\u793a (ER\u5716) |\n|------|------|------|-----------------|\n| **\u5be6\u9ad4** | Entity | \u5177\u9ad4\u7684\u4eba\u4e8b\u7269\uff08\u5982\uff1a\u9867\u5ba2\u3001\u54e1\u5de5\u3001\u90e8\u9580\uff09 | \u77e9\u5f62 \u25ad |\n| **\u5c6c\u6027** | Attribute | \u5be6\u9ad4\u7684\u7279\u5fb5\uff08\u5982\uff1a\u59d3\u540d\u3001\u96fb\u8a71\u3001\u85aa\u6c34\uff09 | \u6a62\u5713\u5f62 \u25ef |\n| **\u95dc\u4fc2** | Relationship| \u5be6\u9ad4\u4e4b\u9593\u7684\u4e92\u52d5\uff08\u5982\uff1a\u9867\u5ba2\u300c\u8cfc\u8cb7\u300d\u5546\u54c1\uff09 | \u83f1\u5f62 \u25c7 |\n\n### \u5be6\u9ad4\u4e4b\u9593\u7684\u95dc\u4fc2\u985e\u578b\uff08Cardinality\uff09\n- **\u4e00\u5c0d\u4e00 (1:1)**\uff1a\u4f8b\u5982\u300c\u4e00\u500b\u54e1\u5de5\u5c0d\u61c9\u4e00\u500b\u54e1\u5de5\u8b58\u5225\u8b49\u300d\u3002\n- **\u4e00\u5c0d\u591a (1:N)**\uff1a\u4f8b\u5982\u300c\u4e00\u500b\u90e8\u9580\u5305\u542b\u591a\u500b\u54e1\u5de5\u300d\u3002\n- **\u591a\u5c0d\u591a (M:N)**\uff1a\u4f8b\u5982\u300c\u4e00\u500b\u5b78\u751f\u53ef\u9078\u591a\u9580\u8ab2\uff0c\u4e00\u9580\u8ab2\u53ef\u88ab\u591a\u500b\u5b78\u751f\u9078\u300d\u3002\n  > \u26a0\ufe0f \u5728\u5be6\u969b\u95dc\u806f\u5f0f\u8cc7\u6599\u5eab\u4e2d\uff0c\u7121\u6cd5\u76f4\u63a5\u5be6\u4f5c\u591a\u5c0d\u591a\u95dc\u4fc2\uff0c\u5fc5\u9808\u900f\u904e\u4e00\u500b**\u300c\u4e2d\u4ecb\u8868\uff08\u95dc\u806f\u8868\uff09\u300d**\u62c6\u89e3\u6210\u5169\u500b\u4e00\u5c0d\u591a\u95dc\u4fc2\u3002\n\n---\n\n## \u4e09\u3001\u95dc\u806f\u5f0f\u8cc7\u6599\u6a21\u578b\u57fa\u790e\u6982\u5ff5\n\n| \u5c08\u6709\u540d\u8a5e | \u8aaa\u660e |\n|----------|------|\n| **\u4e3b\u9375 (Primary Key, PK)** | \u8868\u683c\u4e2d\u7528\u4f86**\u552f\u4e00\u8b58\u5225**\u6bcf\u4e00\u7b46\u8a18\u9304\u7684\u6b04\u4f4d\u3002\u4e0d\u53ef\u91cd\u8907\u3001\u4e0d\u53ef\u70ba\u7a7a (NULL)\u3002 |\n| **\u5916\u9375 (Foreign Key, FK)** | \u7528\u4f86\u5efa\u7acb\u8207\u53e6\u4e00\u5f35\u8868**\u95dc\u806f**\u7684\u6b04\u4f4d\u3002\u5916\u9375\u7684\u503c\u5fc5\u9808\u5b58\u5728\u65bc\u88ab\u53c3\u7167\u8868\u7684\u4e3b\u9375\u4e2d\u3002 |\n| **\u8907\u5408\u9375 (Composite Key)** | \u7531**\u5169\u500b\u6216\u591a\u500b\u6b04\u4f4d**\u7d44\u6210\u7684 PK\uff0c\u7528\u4f86\u5171\u540c\u78ba\u4fdd\u552f\u4e00\u6027\u3002 |\n| **\u5019\u9078\u9375 (Candidate Key)** | \u6709\u8cc7\u683c\u6210\u70ba PK \u7684\u6b04\u4f4d\uff08\u80fd\u552f\u4e00\u8b58\u5225\u8a18\u9304\uff09\u3002 |\n\n---\n\n## \u56db\u3001\u8cc7\u6599\u5eab\u6b63\u898f\u5316 (Normalization)\n\n**\u6b63\u898f\u5316**\u662f\u6574\u7406\u8cc7\u6599\u5eab\u7d50\u69cb\u7684\u904e\u7a0b\uff0c\u76ee\u7684\u662f**\u6e1b\u5c11\u8cc7\u6599\u91cd\u8907\uff08Redundancy\uff09**\u3001**\u907f\u514d\u8cc7\u6599\u66f4\u65b0\u7570\u5e38\uff08Anomaly\uff09**\u3002\n\n### 1NF (\u7b2c\u4e00\u6b63\u898f\u5f62) \u2014 \u5c6c\u6027\u4e0d\u53ef\u518d\u5206\n- **\u898f\u5247**\uff1a\u6bcf\u500b\u6b04\u4f4d\u53ea\u80fd\u5b58\u653e\u55ae\u4e00\u503c\uff08\u4e0d\u80fd\u662f\u9663\u5217\u6216\u6e05\u55ae\uff09\u3002\n- **\u7bc4\u4f8b**\uff1a\u4e00\u500b\u300c\u96fb\u8a71\u300d\u6b04\u4f4d\u4e0d\u80fd\u540c\u6642\u5beb\u300c0912-xxx, 02-xxxx\u300d\uff0c\u5fc5\u9808\u62c6\u958b\u6216\u65b0\u589e\u5217\u3002\n\n### 2NF (\u7b2c\u4e8c\u6b63\u898f\u5f62) \u2014 \u6d88\u9664\u90e8\u4efd\u76f8\u4f9d\n- **\u524d\u63d0**\uff1a\u5fc5\u9808\u5148\u7b26\u5408 1NF\u3002\n- **\u898f\u5247**\uff1a\u975e\u4e3b\u9375\u6b04\u4f4d\u5fc5\u9808\u300c\u5b8c\u5168\u300d\u4f9d\u8cf4\u65bc\u6574\u500b\u4e3b\u9375\uff08\u5982\u679c\u4e3b\u9375\u662f\u8907\u5408\u9375\uff0c\u4e0d\u80fd\u53ea\u4f9d\u8cf4\u5176\u4e2d\u4e00\u90e8\u5206\uff09\u3002\n- **\u7bc4\u4f8b**\uff1a\u5982\u679c\u6709\u8a02\u55ae\u660e\u7d30\u8868\uff08\u8a02\u55aeID, \u5546\u54c1ID \u662f\u8907\u5408\u4e3b\u9375\uff09\uff0c\u300c\u5546\u54c1\u540d\u7a31\u300d\u53ea\u4f9d\u8cf4\u65bc\u300c\u5546\u54c1ID\u300d\uff0c\u9019\u5c31\u662f\u90e8\u4efd\u76f8\u4f9d\uff0c\u8981\u628a\u5546\u54c1\u62c9\u51fa\u53bb\u7368\u7acb\u6210\u5546\u54c1\u8868\u3002\n\n### 3NF (\u7b2c\u4e09\u6b63\u898f\u5f62) \u2014 \u6d88\u9664\u905e\u79fb\u76f8\u4f9d\n- **\u524d\u63d0**\uff1a\u5fc5\u9808\u5148\u7b26\u5408 2NF\u3002\n- **\u898f\u5247**\uff1a\u975e\u4e3b\u9375\u6b04\u4f4d\u4e4b\u9593\u4e0d\u80fd\u6709\u4f9d\u8cf4\u95dc\u4fc2\uff08\u975e\u4e3b\u9375\u6b04\u4f4d\u4e0d\u80fd\u63a8\u5c0e\u51fa\u53e6\u4e00\u500b\u975e\u4e3b\u9375\u6b04\u4f4d\uff09\u3002\n- **\u7bc4\u4f8b**\uff1a\u54e1\u5de5\u8868\u6709\u300c\u90e8\u9580ID\u300d\u548c\u300c\u90e8\u9580\u540d\u7a31\u300d\u3002\u300c\u90e8\u9580\u540d\u7a31\u300d\u5176\u5be6\u4f9d\u8cf4\u65bc\u300c\u90e8\u9580ID\u300d\uff0c\u9019\u5c31\u662f\u905e\u79fb\u76f8\u4f9d\uff0c\u61c9\u8a72\u628a\u90e8\u9580\u8cc7\u8a0a\u7368\u7acb\u6210\u90e8\u9580\u8868\u3002\n\n> \ud83d\udca1 **\u53e3\u8a23**\uff1a\n> 1NF\uff1a\u78ba\u4fdd\u539f\u5b50\u6027\uff08\u55ae\u4e00\u503c\uff09\u3002\n> 2NF\uff1a\u78ba\u4fdd\u5168\u90e8\u4f9d\u8cf4\u4e3b\u9375\u3002\n> 3NF\uff1a\u78ba\u4fdd\u4e0d\u4f9d\u8cf4\u5176\u4ed6\u975e\u4e3b\u9375\u3002\n> \uff08\u901a\u5e38\u505a\u5230 3NF \u5c31\u80fd\u6eff\u8db3\u5927\u90e8\u5206\u696d\u52d9\u9700\u6c42\uff09\n\n---\n\n## \u4e94\u3001\u53cd\u6b63\u898f\u5316 (Denormalization)\n\n\u5728\u67d0\u4e9b\u60c5\u6cc1\u4e0b\uff08\u7279\u5225\u662f\u5927\u6578\u64da\u5206\u6790\u3001\u8cc7\u6599\u5009\u5132\uff09\uff0c\u904e\u5ea6\u6b63\u898f\u5316\u6703\u5c0e\u81f4\u67e5\u8a62\u6642\u9700\u8981\u505a\u592a\u591a\u7684 `JOIN`\uff0c\u56b4\u91cd\u5f71\u97ff\u6548\u80fd\u3002\n**\u53cd\u6b63\u898f\u5316**\u5c31\u662f\u6545\u610f\u6253\u7834\u6b63\u898f\u5316\u898f\u5247\uff0c**\u5bb9\u8a31\u4e00\u5b9a\u7a0b\u5ea6\u7684\u8cc7\u6599\u91cd\u8907**\uff0c\u4f86\u63db\u53d6**\u66f4\u5feb\u7684\u67e5\u8a62\u901f\u5ea6**\uff08\u4ee5\u7a7a\u9593\u63db\u53d6\u6642\u9593\uff09\u3002\n\n---\n\n## \u516d\u3001\u8cc7\u6599\u5009\u5132\u7684\u7dad\u5ea6\u5efa\u6a21 (Dimensional Modeling)\n\n\u9019\u662f\u5927\u6578\u64da\u5206\u6790\u8207\u8cc7\u6599\u5009\u5132\u4e2d\u6700\u5e38\u7528\u7684\u8cc7\u6599\u6a21\u578b\u67b6\u69cb\u3002\u5305\u542b\u5169\u7a2e\u6838\u5fc3\u8868\u683c\uff1a\n\n| \u985e\u578b | \u8aaa\u660e | \u7bc4\u4f8b |\n|------|------|------|\n| **\u4e8b\u5be6\u8868 (Fact Table)** | \u5132\u5b58**\u696d\u52d9\u767c\u751f\u7684\u4e8b\u4ef6\u548c\u6578\u503c\uff08\u5ea6\u91cf\uff09**\u3002\u8cc7\u6599\u91cf\u6975\u5927\uff0c\u901a\u5e38\u53ea\u5b58\u6578\u5b57\u548c FK\u3002 | \u92b7\u552e\u4e8b\u5be6\u8868\uff08\u5305\u542b\uff1a\u92b7\u552e\u91cf\u3001\u91d1\u984d\u3001\u9867\u5ba2ID\u3001\u6642\u9593ID\uff09 |\n| **\u7dad\u5ea6\u8868 (Dimension Table)** | \u5132\u5b58**\u89c0\u5bdf\u4e8b\u5be6\u7684\u89d2\u5ea6\u548c\u63cf\u8ff0\u5c6c\u6027**\u3002\u8cc7\u6599\u91cf\u8f03\u5c0f\uff0c\u5c6c\u6027\u8c50\u5bcc\u3002 | \u9867\u5ba2\u7dad\u5ea6\u8868\uff08\u5305\u542b\uff1a\u59d3\u540d\u3001\u6027\u5225\u3001\u57ce\u5e02\uff09\u3001\u6642\u9593\u7dad\u5ea6\u8868 |\n\n### \u661f\u578b\u6a21\u578b vs \u96ea\u82b1\u6a21\u578b\n\n| \u6a21\u578b | \u661f\u578b\u6a21\u578b (Star Schema) | \u96ea\u82b1\u6a21\u578b (Snowflake Schema) |\n|------|------------------------|-----------------------------|\n| **\u67b6\u69cb** | \u4e00\u500b\u4e8b\u5be6\u8868\u5728\u4e2d\u9593\uff0c\u7dad\u5ea6\u8868\u76f4\u63a5\u570d\u7e5e\u5728\u5468\u570d | \u7dad\u5ea6\u8868\u6703\u518d\u9032\u4e00\u6b65\u5ef6\u4f38\u51fa\u5176\u4ed6\u7dad\u5ea6\u8868 |\n| **\u6b63\u898f\u5316\u7a0b\u5ea6** | \u4f4e\uff08\u7dad\u5ea6\u8868\u901a\u5e38\u672a\u6b63\u898f\u5316\uff0c\u6709\u5197\u9918\u8cc7\u6599\uff09 | \u9ad8\uff08\u7dad\u5ea6\u8868\u7d93\u904e\u6b63\u898f\u5316\uff09 |\n| **\u67e5\u8a62\u6548\u80fd** | **\u8f03\u5feb**\uff08JOIN \u7684\u8868\u8f03\u5c11\uff09 | \u8f03\u6162\uff08\u9700\u8981 JOIN \u591a\u5f35\u8868\uff09 |\n| **\u7dad\u8b77\u8907\u96dc\u5ea6** | \u8f03\u7c21\u55ae | \u8f03\u8907\u96dc |\n\n> \ud83d\udca1 \u5728\u5927\u6578\u64da\u8cc7\u6599\u5009\u5132\u4e2d\uff0c\u901a\u5e38\u504f\u597d\u4f7f\u7528**\u661f\u578b\u6a21\u578b**\uff0c\u56e0\u70ba\u67e5\u8a62\u6548\u80fd\u8f03\u4f73\u3002\n\n---\n\n## \u5e38\u898b\u8003\u984c\u901f\u8a18\n\n| \u984c\u578b\u95dc\u9375\u5b57 | \u5c0d\u61c9\u6982\u5ff5 |\n|------------|----------|\n| \u8cc7\u6599\u5eab\u5efa\u6a21\u7684\u4e09\u968e\u6bb5 | \u6982\u5ff5\u6a21\u578b \u2192 \u908f\u8f2f\u6a21\u578b \u2192 \u5be6\u9ad4\u6a21\u578b |\n| ER \u5716\u4e2d\u7684\u83f1\u5f62\u4ee3\u8868\u4ec0\u9ebc | \u95dc\u4fc2 (Relationship) |\n| \u80fd\u552f\u4e00\u8b58\u5225\u8a18\u9304\u7684\u6b04\u4f4d | \u4e3b\u9375 (Primary Key) |\n| \u6bcf\u500b\u6b04\u4f4d\u53ea\u80fd\u6709\u55ae\u4e00\u503c | 1NF (\u7b2c\u4e00\u6b63\u898f\u5f62) |\n| \u6e1b\u5c11\u8cc7\u6599\u5197\u9918\u3001\u907f\u514d\u66f4\u65b0\u7570\u5e38 | \u6b63\u898f\u5316 (Normalization) |\n| \u70ba\u4e86\u67e5\u8a62\u6548\u80fd\u6545\u610f\u589e\u52a0\u8cc7\u6599\u5197\u9918 | \u53cd\u6b63\u898f\u5316 (Denormalization) |\n| \u5132\u5b58\u696d\u52d9\u6578\u503c\u8207\u5ea6\u91cf\u7684\u8868\u683c | \u4e8b\u5be6\u8868 (Fact Table) |\n| \u67e5\u8a62\u6700\u5feb\uff0c\u7dad\u5ea6\u8868\u4e0d\u6b63\u898f\u5316\u7684\u8cc7\u6599\u5009\u5132\u6a21\u578b | \u661f\u578b\u6a21\u578b (Star Schema) |\n| \u95dc\u806f\u8cc7\u6599\u5eab\u5982\u4f55\u5be6\u4f5c\u591a\u5c0d\u591a\u95dc\u4fc2 | \u900f\u904e\u7b2c\u4e09\u5f35\u95dc\u806f\u8868\uff08\u4e2d\u4ecb\u8868\uff09\u62c6\u6210\u5169\u500b\u4e00\u5c0d\u591a |\n\n---\n\n*\ud83d\udcdd by \u751c\u8766 \ud83c\udf64 | 2026.04.20*\n"};